import{_ as t,C as n,o as l,c as p,j as a,a as i,E as h,ae as o}from"./chunks/framework.CbfcRfVi.js";const b=JSON.parse('{"title":"Post installation things","description":"","frontmatter":{},"headers":[],"relativePath":"ps4/post-install.md","filePath":"ps4/post-install.md","lastUpdated":1777872142000}'),d={name:"ps4/post-install.md"},r={id:"update-your-system",tabindex:"-1"};function k(c,s,g,u,F,y){const e=n("Badge");return l(),p("div",null,[s[3]||(s[3]=a("h1",{id:"post-installation-things",tabindex:"-1"},[i("Post installation things "),a("a",{class:"header-anchor",href:"#post-installation-things","aria-label":'Permalink to "Post installation things"'},"​")],-1)),s[4]||(s[4]=a("p",null,"Once you've installed Linux and are on the desktop, before rushing to do things, you may want to do a couple of additional steps.",-1)),s[5]||(s[5]=a("p",null,[i("To change some config files (don't worry, it won't hurt), I'll recommend "),a("code",null,"nano"),i(" because it just works. To save a file, use "),a("code",null,"CTRL+S"),i(" and to exit "),a("code",null,"CTRL+X"),i(".")],-1)),a("h2",r,[s[0]||(s[0]=i("Update your system ",-1)),h(e,{type:"danger",text:"caution"}),s[1]||(s[1]=i()),s[2]||(s[2]=a("a",{class:"header-anchor",href:"#update-your-system","aria-label":'Permalink to "Update your system <Badge type="danger" text="caution" />"'},"​",-1))]),s[6]||(s[6]=o(`<p>Updating your system can be a bit of a pain in the ass, as some of the packages can&#39;t be updated because they contain modifications to make them work on the PS4.</p><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>Arch-based distros have repositories for drivers, other distros might not.</p></div><details class="details custom-block"><summary>Arch based distros (with driver updates)</summary><p>To update the drivers, you need to open the pacman config:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/pacman.conf</span></span></code></pre></div><p>If you installed a distro from the forums, you may have go to the <code>[Options]</code> section and delete the lines <code>IgnorePkg</code> and <code>IgnoreGroup</code>.</p><p>Then, under the <code>REPOSITORIES</code> section, add this (<a href="https://github.com/DionKill/ps4-video-archlinux" target="_blank" rel="noreferrer">GitHub</a>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ps4-video]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SigLevel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Optional</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://dionkill.github.io/ps4-video-archlinux/repo/</span></span></code></pre></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>This repo will only work as long as the developer is updating it and keeping it online. It may be changed in the future.</p></div><p>Then, <code>CTRL+S</code> to save and <code>CTRL+X</code> to exit.</p><p>Finally, install the driver packages:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Syu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-mesa-ps4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mesa-ps4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-libdrm-ps4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libdrm-ps4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xf86-video-amdgpu-ps4</span></span></code></pre></div><p>You should now have up-to-date drivers.</p></details><details class="details custom-block"><summary>Debian/Ubuntu based distros (WITH Mesa updates, WIP)</summary><p>Use triki1&#39;s updater (should be included in their distro releases now)</p><p>Use uar&#39;s script updater:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [https://uar.no/ps4/baikal/mesa-25.sh](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://uar.no/ps4/baikal/mesa-25.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://uar.no/ps4/baikal/mesa-25.sh&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mesa-25.sh</span></span></code></pre></div></details><details class="details custom-block"><summary>Debian/Ubuntu based distros (disabled Mesa updates)</summary><p>To make sure that the PS4 packages don&#39;t get updated run the command below:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-mark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hold</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-libdrm-git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-mesa-git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libdrm-git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mesa-git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-libdrm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-mesa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libdrm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mesa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-llvm-libs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> llvm-libs</span></span></code></pre></div><p>Then, you should be free to update your system with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span></code></pre></div></details><details class="details custom-block"><summary>Fedora based distros (untested)</summary><p>To make sure that the PS4 packages don&#39;t get updated, you need to modify the dnf config:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/dnf/dnf.conf</span></span></code></pre></div><p>Then, at the line next to the <code>[main]</code> section:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">exclude</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">lib32-libdrm-git</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> lib32-mesa-git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libdrm-git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mesa-git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-libdrm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-mesa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libdrm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mesa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lib32-llvm-libs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> llvm-libs</span></span></code></pre></div><p>Then, you should be free to update your system with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div></details><p>Otherwise, you can always update everything but not the driver packages.</p><h2 id="fix-language" tabindex="-1">Fix language <a class="header-anchor" href="#fix-language" aria-label="Permalink to &quot;Fix language&quot;">​</a></h2><p>Some pre-packaged distros you can download are in foreign languages. Unfortunately changing it from your DE (KDE, Gnome...) doesn&#39;t apply system wide. So here&#39;s a cheap rundown of all of the commands:</p><details class="details custom-block"><summary>Debian/Ubuntu based distros (thanks triky1)</summary><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dpkg-reconfigure</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> locales</span></span></code></pre></div></details><details class="details custom-block"><summary>Fedora based distros (to-do)</summary><p>Nobody knows</p></details><details class="details custom-block"><summary>Arch based distros</summary><p>You first need to edit your <code>locale.gen</code>, to generate your locale settings.</p><p>Comment out any language you don&#39;t want and uncomment yours:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/locale.gen</span></span></code></pre></div><p>Now, you can generate your locale with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> locale-gen</span></span></code></pre></div><p>And last but not least, to change it system wide, add your language in this file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/locale.conf</span></span></code></pre></div><p>If needed, change your language in yout DE (KDE, Gnome...)</p></details><p>Reboot to apply these changes.</p><h2 id="change-username-and-password" tabindex="-1">Change username and password <a class="header-anchor" href="#change-username-and-password" aria-label="Permalink to &quot;Change username and password&quot;">​</a></h2><p>Honestly? Create a new user. It&#39;s faster. Or just keep it.</p><p>You can however change the password, by doing:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> passwd</span></span></code></pre></div><p>And setting a new password.</p><h2 id="better-ram-management" tabindex="-1">Better ram management <a class="header-anchor" href="#better-ram-management" aria-label="Permalink to &quot;Better ram management&quot;">​</a></h2><p>To do that, we must use Swap or ZRAM. Do not use both because it will have negative effects on the ps4.</p><details class="details custom-block"><summary>Enabling Swap</summary><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p>It&#39;s ABSOLUTELY NOT recommended to use the internal HDD as swap, you&#39;d just add fuel to the dumpsterfire of slowness that it already is. Disable it and move on.</p></div><p>Swap is storage that you are taking from your drive and allocating as &quot;extra RAM&quot;: it works by moving unused software over there if extra main memory needs to be reserved for another program or game. This means we can improve the memory situation a little bit.</p><p>We will be using a swap file instead of a swap partition, as it&#39;s easier to change in size. First of all, we need to remove any existing swap:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swapoff</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span></code></pre></div><p>Then, we need to enable new swap (8GB for this tutorial, you may change it)</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fallocate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8G</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8GB</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Allocates 8GBs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkswap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swapon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span></code></pre></div><p>Finally, go to the <code>fstab</code> file, and check if the line <code>/swapfile none swap sw 0 0</code> exists. If it doesn&#39;t, add it by going here and pasting it at the end of the file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/fstab</span></span></code></pre></div></details><details class="details custom-block"><summary>Enabling ZRAM</summary><p>ZRAM on the other hand, is a part of your memory that you are compressing and allocating as swap. A kernel that supports it is necessary.</p><p>This means that we trade some CPU cycles for compressing and decompressing a part of your system memory. If it is enabled by default on Android you can guess how little performance impact there is.</p><p>To enable ZRAM, we need to install the <code>zram-generator</code> package. On Arch, we installing using:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Syu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zram-generator</span></span></code></pre></div><p>We then create the config file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/lib/systemd/zram-generator.conf</span></span></code></pre></div><p>And we paste this inside of it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[zram0]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">zram-size</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">compression-algorithm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">zstd</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">swap-priority</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">60</span></span></code></pre></div><p><code>zram-size</code> is how much RAM we are allocating for the ZRAM device. Possible values are, for example, <code>50%</code>, <code>2G</code> (i.e. 2 GB), <code>ram</code> or <code>max</code> for maximum allocation (all RAM is ZRAM). Don&#39;t change the other values unless you really know what you&#39;re doing.</p><p>It is also recommended to disable ZSWAP. Some distro already do this, but just in case go to your grub config:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/default/grub</span></span></code></pre></div><p>And in the <code>LINUX_CMDLINE_DEFAULT</code> check that <code>zswap-enabled=0</code> is present. If not, add it.</p></details><details class="details custom-block"><summary>Disabling ZRAM (if you need to)</summary><p>To disable ZRAM, in case of swapping out kernels often for instance, you can simply remove the config file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/systemd/zram-generator.conf</span></span></code></pre></div><p>However, if you wish to completely remove it, do the following:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> disable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zram-generator.service</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # This may not be needed</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Rns</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zram-generator</span></span></code></pre></div><p>Also, remove the swap partitions:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swapoff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/zram0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/zram0</span></span></code></pre></div><p>Then reboot the system. It should be gone.</p><p>Thanks again to Qba for this <a href="https://youtu.be/f_kXks8z9dc" target="_blank" rel="noreferrer">showcase</a>.</p></details><p>Oh, and don&#39;t worry if you see that your installation is using a lot of memory. It&#39;s normal and is meant to happen in order to improve performance. Check this <a href="https://linuxatemyram.com" target="_blank" rel="noreferrer">link</a> to learn more.</p><h2 id="get-more-cpu-performance" tabindex="-1">Get more CPU performance <a class="header-anchor" href="#get-more-cpu-performance" aria-label="Permalink to &quot;Get more CPU performance&quot;">​</a></h2><p>You may have realized that the PS4&#39;s CPU is pretty lacking and is most likely it&#39;s biggest disadvantage. But apart from a really optimized distro, what else can you do?</p><p>In computing you are always going to gain something and loose something else. Either your time, money, or in this case...</p><details class="details custom-block"><summary>Disable Cpu mitigations</summary><p>Yes, you can disable some security patches for attacks like Meltdown and Spectre, to gain some CPU performance. It does work and should have a noticeable improvement.</p><p>Obviously this is usually not recommended, but if all you want to do is game from your Steam library and occasionally browse the web (which is most of us), you are probably going to be fine. Also remember the console is already jailbroken... Not really going for security with that one.</p><p>To do that it&#39;s surprisingly simple. Open the <code>bootargs.txt</code> file, or create it in the same folder of the kernel if it doesn&#39;t exist already, then add this line, save and reboot:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mitigations</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">off</span></span></code></pre></div><p>And there you go! You can change it back anytime of course.</p></details><p>Do not go and download an older kernel to try as they don&#39;t work anymore either!</p><h2 id="install-more-applications" tabindex="-1">Install more applications <a class="header-anchor" href="#install-more-applications" aria-label="Permalink to &quot;Install more applications&quot;">​</a></h2><p>To play games, these are the recommended softwares:</p><ul><li>Steam</li><li>Heroic Games Launcher (for Epic, GOG and Amazon)</li><li>Lutris (for other PC games not in those launchers)</li><li>Fjord Launcher instead of those other shitty Minecraft launchers <ul><li>Minecraft has graphical issues in versions newer than 1.21.5</li></ul></li><li>And a bunch of emulators!</li></ul><p>To do that, if using anything other than Arch based distros, install from their repo or github.</p><p>If you chose an Arch based distro however, use <code>pacman</code> or <code>yay</code> to install your packages. All packages you can even think of and more are available.</p>`,34))])}const C=t(d,[["render",k]]);export{b as __pageData,C as default};
